801	\begin{theorem}\leanok
802	[Linear hom-equivalence from an adjunction]
803	  \label{def:Adjunction_homLinearEquiv}
804	  \lean{CategoryTheory.Adjunction.homLinearEquiv}
805	  \uses{lemma:Adjunction_left_adjoint_linear}
806	  Let $\mathtt{adj} : F \dashv G$ between $R$-linear preadditive categories with $F.\mathtt{Additive}$, $G.\mathtt{Additive}$, $G.\mathtt{Linear}\,R$. Then for all objects $X$ and $Y$, the additive equivalence $\mathtt{adj.homAddEquiv}\,X\,Y$ upgrades to a $\LinearEquiv$ over $R$:
807	  \[
808	    (F.\mathtt{obj}\,X \to Y) \;\equivl{R}\; (X \to G.\mathtt{obj}\,Y).
809	  \]
810	\end{theorem}
